import axios from "axios";

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL || "";
export const API_BASE = `${BACKEND_URL}/api`;

export const api = axios.create({
  baseURL: API_BASE,
  headers: {
    "Content-Type": "application/json",
  },
});

// Direct download link for the generated CV PDF
export const cvDownloadUrl = `${API_BASE}/cv`;

/**
 * Submit the contact form.
 * @param {{name: string, email: string, subject?: string, message: string}} payload
 * @returns {Promise<object>} saved contact message
 */
export const sendContactMessage = async (payload) => {
  const { data } = await api.post("/contact", payload);
  return data;
};

/**
 * Simple health check against the API root.
 */
export const checkHealth = async () => {
  const { data } = await api.get("/");
  return data;
};
